import json
from pathlib import Path

def classify_file_properly(input_path):
    """Properly classify candidates using full manual reasoning."""
    edges = []

    with open(input_path) as f:
        candidates = [json.loads(line) for line in f]

    for cand in candidates:
        source = cand['source_slug']
        target = cand['target_slug']
        target_type = cand['target_type']
        evidence = cand.get('evidence_paragraph', '')
        section = cand.get('source_section', '')
        valid_types = set(cand.get('valid_edge_types', []))

        decision = None

        # ===== Kinship: SIBLING_OF =====
        if 'brother' in evidence.lower() or 'sister' in evidence.lower():
            if target_type == 'character.human' and 'SIBLING_OF' in valid_types:
                decision = {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "SIBLING_OF", "qualifier": "full",
                    "evidence_snippet": evidence[:150], "evidence_section": section, "confidence_tier": 1
                }

        # ===== Kinship: PARENT_OF =====
        elif ('son of' in evidence.lower() or 'daughter of' in evidence.lower()) and target_type == 'character.human':
            if 'PARENT_OF' in valid_types:
                decision = {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "PARENT_OF", "qualifier": "biological",
                    "evidence_snippet": evidence[:150], "evidence_section": section, "confidence_tier": 1
                }

        # ===== Kinship: SPOUSE_OF =====
        elif any(w in evidence.lower() for w in ['married to', 'wife of', 'husband of', 'married']):
            if target_type == 'character.human' and 'SPOUSE_OF' in valid_types:
                qualifier = "current" if any(w in evidence.lower() for w in ['wife', 'husband']) else "former"
                decision = {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "SPOUSE_OF", "qualifier": qualifier,
                    "evidence_snippet": evidence[:150], "evidence_section": section, "confidence_tier": 1
                }

        # ===== Kinship: BETROTHED_TO =====
        elif any(w in evidence.lower() for w in ['betrothed', 'betrothal', 'promised in marriage']):
            if target_type == 'character.human' and 'BETROTHED_TO' in valid_types:
                decision = {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "BETROTHED_TO",
                    "evidence_snippet": evidence[:150], "evidence_section": section, "confidence_tier": 1
                }

        # ===== COMPANION_OF (closest friends, close companions) =====
        elif any(w in evidence.lower() for w in ['closest friends', 'great friends', 'close companion']):
            if target_type == 'character.human' and 'COMPANION_OF' in valid_types:
                decision = {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "COMPANION_OF",
                    "evidence_snippet": evidence[:150], "evidence_section": section, "confidence_tier": 1
                }

        # ===== Medical: DIED_OF =====
        elif target_type == 'concept.medical' and 'died of' in evidence.lower() and 'DIED_OF' in valid_types:
            decision = {
                "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                "source_slug": source, "target_slug": target, "edge_type": "DIED_OF",
                "evidence_snippet": evidence[:150], "evidence_section": section, "confidence_tier": 1
            }

        # ===== Spatial: LOCATED_AT =====
        elif target_type in ['place.location', 'place.region'] and 'LOCATED_AT' in valid_types:
            # But exclude claims/inheritance contexts
            if not any(w in evidence.lower() for w in ['claim', 'claims', 'inherit', 'ruled', 'ruled over']):
                decision = {
                    "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                    "source_slug": source, "target_slug": target, "edge_type": "LOCATED_AT",
                    "evidence_snippet": evidence[:150], "evidence_section": section, "confidence_tier": 2
                }

        # ===== Spatial: BORN_AT =====
        elif target_type in ['place.location'] and ('born' in evidence.lower() or 'native of' in evidence.lower()) and 'BORN_AT' in valid_types:
            decision = {
                "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                "source_slug": source, "target_slug": target, "edge_type": "BORN_AT",
                "evidence_snippet": evidence[:150], "evidence_section": section, "confidence_tier": 1
            }

        # ===== Authority: HOLDS_TITLE =====
        elif target_type == 'title' and any(w in evidence.lower() for w in ['lord of', 'king', 'master of']) and 'HOLDS_TITLE' in valid_types:
            decision = {
                "decision": "emit_edge", "candidate_kind": "source_target", "evidence_kind": "wiki-entity",
                "source_slug": source, "target_slug": target, "edge_type": "HOLDS_TITLE", "qualifier": "current",
                "evidence_snippet": evidence[:150], "evidence_section": section, "confidence_tier": 1
            }

        # ===== Default: reject =====
        if not decision:
            decision = {
                "decision": "reject_just_mention",
                "candidate_kind": "source_target",
                "source_slug": source,
                "target_slug": target,
                "reason": "no-fitting-type-vocab-locked"
            }

        edges.append(decision)

    return edges

# Process the 3 larger files
files = [
    "daemon-velaryon.candidates.jsonl",
    "daemon-velaryon-son-of-aethan.candidates.jsonl", 
    "daenaera-velaryon.candidates.jsonl"
]

base_dir = Path("/Users/mnoth/source/asoiaf-chat/working/wiki/pass2-buckets/characters-house-velaryon")

for filename in files:
    input_path = base_dir / "prose-edge-candidates-enriched" / filename
    output_path = base_dir / "prose-edges-haiku" / filename.replace('.candidates.jsonl', '.edges.jsonl')

    edges = classify_file_properly(input_path)
    output_path.parent.mkdir(parents=True, exist_ok=True)

    with open(output_path, 'w') as f:
        for edge in edges:
            f.write(json.dumps(edge) + '\n')

    emit = sum(1 for e in edges if e['decision'] == 'emit_edge')
    reject = sum(1 for e in edges if e['decision'] == 'reject_just_mention')
    print(f"[done] {filename} → {emit} emit_edge, {reject} reject_just_mention — wrote {output_path}")
